package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="audit_cycle_auditors") @IdClass(AuditCycleAuditor.Key.class) public class AuditCycleAuditor { @Id @Column(name="audit_cycle_id") public Long auditCycleId; @Id @Column(name="auditor_user_id") public Long auditorUserId; @Column(name="assigned_at",nullable=false) public OffsetDateTime assignedAt; @PrePersist void created(){if(assignedAt==null)assignedAt=OffsetDateTime.now(ZoneOffset.UTC);} public static class Key implements java.io.Serializable { public Long auditCycleId; public Long auditorUserId; public Key(){} @Override public boolean equals(Object value){return value instanceof Key key&&Objects.equals(auditCycleId,key.auditCycleId)&&Objects.equals(auditorUserId,key.auditorUserId);}@Override public int hashCode(){return Objects.hash(auditCycleId,auditorUserId);} } }
